// Cloudflare Worker for Edge Authentication System
// KV Namespaces required (configured in wrangler.toml):
// - USERS_KV: stores user records (key: username, value: JSON with hashed password, salt, metadata)
// - SESSIONS_KV: stores session tokens (key: token, value: JSON with username, created_at, expires_at)
// - CONFIG_KV: stores configuration like API keys, database connection strings

const SESSION_TTL = 3600; // 1 hour in seconds
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_DURATION = 900; // 15 minutes in seconds
const TOKEN_LENGTH = 32;

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    // CORS headers for preflight
    if (request.method === "OPTIONS") {
      return handleCORS();
    }

    try {
      switch (url.pathname) {
        case "/auth/register":
          return await handleRegister(request, env);
        case "/auth/login":
          return await handleLogin(request, env);
        case "/auth/logout":
          return await handleLogout(request, env);
        case "/auth/validate":
          return await handleValidateSession(request, env);
        case "/auth/refresh":
          return await handleRefreshSession(request, env);
        default:
          return jsonResponse({ error: "Not Found" }, 404);
      }
    } catch (err) {
      console.error("Unhandled error:", err.message);
      return jsonResponse({ error: "Internal Server Error" }, 500);
    }
  },
};

// --- Cryptographic Utilities ---

async function hashPassword(password, salt) {
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    "raw",
    encoder.encode(password),
    "PBKDF2",
    false,
    ["deriveBits"]
  );

  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      salt: hexToBuffer(salt),
      iterations: 100000,
      hash: "SHA-256",
    },
    keyMaterial,
    256
  );

  return bufferToHex(derivedBits);
}

function generateSalt() {
  const salt = new Uint8Array(16);
  crypto.getRandomValues(salt);
  return bufferToHex(salt);
}

async function generateSessionToken() {
  const buffer = new Uint8Array(TOKEN_LENGTH);
  crypto.getRandomValues(buffer);
  return bufferToHex(buffer);
}

function bufferToHex(buffer) {
  return [...new Uint8Array(buffer)]
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

function hexToBuffer(hex) {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
  }
  return bytes.buffer;
}

// Constant-time string comparison to prevent timing attacks
function secureCompare(a, b) {
  if (typeof a !== "string" || typeof b !== "string") return false;
  if (a.length !== b.length) return false;

  const encoder = new TextEncoder();
  const bufA = encoder.encode(a);
  const bufB = encoder.encode(b);

  let result = 0;
  for (let i = 0; i < bufA.length; i++) {
    result |= bufA[i] ^ bufB[i];
  }
  return result === 0;
}

// --- Rate Limiting ---

async function checkRateLimit(env, identifier) {
  const key = `ratelimit:${identifier}`;
  const record = await env.SESSIONS_KV.get(key, { type: "json" });

  if (!record) {
    return { allowed: true, attempts: 0 };
  }

  if (record.lockedUntil && Date.now() < record.lockedUntil) {
    const retryAfter = Math.ceil((record.lockedUntil - Date.now()) / 1000);
    return { allowed: false, attempts: record.attempts, retryAfter };
  }

  // Reset if lockout has expired
  if (record.lockedUntil && Date.now() >= record.lockedUntil) {
    await env.SESSIONS_KV.delete(key);
    return { allowed: true, attempts: 0 };
  }

  if (record.attempts >= MAX_LOGIN_ATTEMPTS) {
    const lockedUntil = Date.now() + LOCKOUT_DURATION * 1000;
    await env.SESSIONS_KV.put(
      key,
      JSON.stringify({ attempts: record.attempts, lockedUntil }),
      { expirationTtl: LOCKOUT_DURATION }
    );
    return {
      allowed: false,
      attempts: record.attempts,
      retryAfter: LOCKOUT_DURATION,
    };
  }

  return { allowed: true, attempts: record.attempts };
}

async function recordFailedAttempt(env, identifier) {
  const key = `ratelimit:${identifier}`;
  const record = await env.SESSIONS_KV.get(key, { type: "json" });

  const attempts = record ? record.attempts + 1 : 1;
  const data = { attempts, lastAttempt: Date.now() };

  if (attempts >= MAX_LOGIN_ATTEMPTS) {
    data.lockedUntil = Date.now() + LOCKOUT_DURATION * 1000;
  }

  await env.SESSIONS_KV.put(key, JSON.stringify(data), {
    expirationTtl: LOCKOUT_DURATION,
  });
}

async function resetRateLimit(env, identifier) {
  const key = `ratelimit:${identifier}`;
  await env.SESSIONS_KV.delete(key);
}

// --- Input Validation ---

function validateUsername(username) {
  if (!username || typeof username !== "string") {
    return { valid: false, error: "Username is required" };
  }
  if (username.length < 3 || username.length > 64) {
    return {
      valid: false,
      error: "Username must be between 3 and 64 characters",
    };
  }
  if (!/^[a-zA-Z0-9_\-@.]+$/.test(username)) {
    return {
      valid: false,
      error:
        "Username contains invalid characters. Only alphanumeric, _, -, @, and . are allowed",
    };
  }
  return { valid: true };
}

function validatePassword(password) {
  if (!password || typeof password !== "string") {
    return { valid: false, error: "Password is required" };
  }
  if (password.length < 8 || password.length > 128) {
    return {
      valid: false,
      error: "Password must be between 8 and 128 characters",
    };
  }
  return { valid: true };
}

// --- Request Helpers ---

function getClientIP(request) {
  return request.headers.get("CF-Connecting-IP") || "unknown";
}

async function parseJSONBody(request) {
  const contentType = request.headers.get("Content-Type") || "";
  if (!contentType.includes("application/json")) {
    throw new Error("Content-Type must be application/json");
  }

  const body = await request.text();
  if (body.length > 10240) {
    throw new Error("Request body too large");
  }

  return JSON.parse(body);
}

function extractBearerToken(request) {
  const authHeader = request.headers.get("Authorization") || "";
  if (!authHeader.startsWith("Bearer ")) {
    return null;
  }
  const token = authHeader.substring(7).trim();
  if (!/^[a-f0-9]{64}$/.test(token)) {
    return null;
  }
  return token;
}

// --- Response Helpers ---

function jsonResponse(data, status = 200, extraHeaders = {}) {
  const headers = {
    "Content-Type": "application/json",
    "X-Content-Type-Options": "nosniff",
    "X-Frame-Options": "DENY",
    "Cache-Control": "no-store, no-cache, must-revalidate",
    "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
    "Access-Control-Allow-Origin": "*", // Restrict in production
    "Access-Control-Allow-Methods": "POST, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization",
    ...extraHeaders,
  };

  return new Response(JSON.stringify(data), { status, headers });
}

function handleCORS() {
  return new Response(null, {
    status: 204,
    headers: {
      "Access-Control-Allow-Origin": "*", // Restrict in production
      "Access-Control-Allow-Methods": "POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type, Authorization",
      "Access-Control-Max-Age": "86400",
    },
  });
}

// --- Route Handlers ---

async function handleRegister(request, env) {
  if (request.method !== "POST") {
    return jsonResponse({ error: "Method Not Allowed" }, 405);
  }

  let body;
  try {
    body = await parseJSONBody(request);
  } catch (e) {
    return jsonResponse({ error: e.message }, 400);
  }

  const { username, password, email } = body;

  // Validate inputs
  const usernameValidation = validateUsername(username);
  if (!usernameValidation.valid) {
    return jsonResponse({ error: usernameValidation.error }, 400);
  }

  const passwordValidation = validatePassword(password);
  if (!passwordValidation.valid) {
    return jsonResponse({ error: passwordValidation.error }, 400);
  }

  // Normalize username to lowercase for consistent lookups
  const normalizedUsername = username.toLowerCase();

  // Check if user already exists
  const existingUser = await env.USERS_KV.get(`user:${normalizedUsername}`);
  if (existingUser) {
    // Return generic message to prevent user enumeration
    return jsonResponse(
      { error: "Registration failed. Please try again." },
      409
    );
  }

  // Hash password with salt
  const salt = generateSalt();
  const hashedPassword = await hashPassword(password, salt);

  const userRecord = {
    username: normalizedUsername,
    passwordHash: hashedPassword,
    salt: salt,
    email: email || null,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    active: true,
  };

  await env.USERS_KV.put(
    `user:${normalizedUsername}`,
    JSON.stringify(userRecord)
  );

  return jsonResponse(
    {
      success: true,
      message: "User registered successfully",
      username: normalizedUsername,
    },
    201
  );
}

async function handleLogin(request, env) {
  if (request.method !== "POST") {
    return jsonResponse({ error: "Method Not Allowed" }, 405);
  }

  const clientIP = getClientIP(request);

  // Check rate limit by IP
  const ipRateLimit = await checkRateLimit(env, `ip:${clientIP}`);
  if (!ipRateLimit.allowed) {
    return jsonResponse(
      {
        error: "Too many login attempts. Please try again later.",
        retryAfter: ipRateLimit.retryAfter,
      },
      429,
      { "Retry-After": String(ipRateLimit.retryAfter) }
    );
  }

  let body;
  try {
    body = await parseJSONBody(request);
  } catch (e) {
    return jsonResponse({ error: e.message }, 400);
  }

  const { username, password } = body;

  // Basic validation
  if (
    !username ||
    !password ||
    typeof username !== "string" ||
    typeof password !== "string"
  ) {
    return jsonResponse({ error: "Username and password are required" }, 400);
  }

  const normalizedUsername = username.toLowerCase();

  // Check rate limit by username
  const userRateLimit = await checkRateLimit(
    env,
    `user:${normalizedUsername}`
  );
  if (!userRateLimit.allowed) {
    return jsonResponse(
      {
        error: "Account temporarily locked due to too many failed attempts.",
        retryAfter: userRateLimit.retryAfter,
      },
      429,
      { "Retry-After": String(userRateLimit.retryAfter) }
    );
  }

  // Fetch user from KV
  const userDataRaw = await env.USERS_KV.get(`user:${normalizedUsername}`);

  if (!userDataRaw) {
    // Record failed attempt even for non-existent users (prevent enumeration)
    await recordFailedAttempt(env, `ip:${clientIP}`);
    // Perform a dummy hash to prevent timing attacks
    const dummySalt = generateSalt();
    await hashPassword(password, dummySalt);
    return jsonResponse({ error: "Invalid username or password" }, 401);
  }

  const userData = JSON.parse(userDataRaw);

  if (!userData.active) {
    return jsonResponse({ error: "Account is deactivated" }, 403);
  }

  // Verify password
  const hashedAttempt = await hashPassword(password, userData.salt);
  const passwordMatch = secureCompare(hashedAttempt, userData.passwordHash);

  if (!passwordMatch) {
    await recordFailedAttempt(env, `ip:${clientIP}`);
    await recordFailedAttempt(env, `user:${normalizedUsername}`);
    return jsonResponse({ error: "Invalid username or password" }, 401);
  }

  // Reset rate limits on successful login
  await resetRateLimit(env, `ip:${clientIP}`);
  await resetRateLimit(env, `user:${normalizedUsername}`);

  // Generate session token
  const sessionToken = await generateSessionToken();
  const now = Date.now();
  const expiresAt = now + SESSION_TTL * 1000;

  const sessionData = {
    username: normalizedUsername,
    createdAt: new Date(now).toISOString(),
    expiresAt: new Date(expiresAt).toISOString(),
    expiresAtMs: expiresAt,
    clientIP: clientIP,
    userAgent: request.headers.get("User-Agent") || "unknown",
  };

  // Store session in KV with TTL
  await env.SESSIONS_KV.put(
    `session:${sessionToken}`,
    JSON.stringify(sessionData),
    { expirationTtl: SESSION_TTL }
  );

  // Also maintain a user-to-sessions index for session management
  const userSessionsKey = `user_sessions:${normalizedUsername}`;
  const existingSessions = await env.SESSIONS_KV.get(userSessionsKey, {
    type: "json",
  });
  const sessions = existingSessions || [];
  // Clean up expired sessions from the index
  const activeSessions = sessions.filter((s) => s.expiresAtMs > now);
  activeSessions.push({
    token: sessionToken,
    expiresAtMs: expiresAt,
    createdAt: sessionData.createdAt,
  });
  await env.SESSIONS_KV.put(
    userSessionsKey,
    JSON.stringify(activeSessions),
    { expirationTtl: SESSION_TTL }
  );

  return jsonResponse({
    success: true,
    token: sessionToken,
    expiresAt: sessionData.expiresAt,
    expiresIn: SESSION_TTL,
    username: normalizedUsername,
  });
}

async function handleLogout(request, env) {
  if (request.method !== "POST") {
    return jsonResponse({ error: "Method Not Allowed" }, 405);
  }

  const token = extractBearerToken(request);
  if (!token) {
    return jsonResponse({ error: "Missing or invalid authorization token" }, 401);
  }

  const sessionKey = `session:${token}`;
  const sessionDataRaw = await env.SESSIONS_KV.get(sessionKey);

  if (sessionDataRaw) {
    const sessionData = JSON.parse(sessionDataRaw);

    // Remove from user sessions index
    const userSessionsKey = `user_sessions:${sessionData.username}`;
    const existingSessions = await env.SESSIONS_KV.get(userSessionsKey, {
      type: "json",
    });
    if (existingSessions) {
      const updatedSessions = existingSessions.filter(
        (s) => s.token !== token
      );
      if (updatedSessions.length > 0) {
        await env.SESSIONS_KV.put(
          userSessionsKey,
          JSON.stringify(updatedSessions),
          { expirationTtl: SESSION_TTL }
        );
      } else {
        await env.SESSIONS_KV.delete(userSessionsKey);
      }
    }

    // Delete the session
    await env.SESSIONS_KV.delete(sessionKey);
  }

  return jsonResponse({
    success: true,
    message: "Logged out successfully",
  });
}

async function handleValidateSession(request, env) {
  if (request.method !== "POST") {
    return jsonResponse({ error: "Method Not Allowed" }, 405);
  }

  const token = extractBearerToken(request);
  if (!token) {
    return jsonResponse({ error: "Missing or invalid authorization token" }, 401);
  }

  const sessionKey = `session:${token}`;
  const sessionDataRaw = await env.SESSIONS_KV.get(sessionKey);

  if (!sessionDataRaw) {
    return jsonResponse({ error: "Invalid or expired session" }, 401);
  }

  const sessionData = JSON.parse(sessionDataRaw);

  // Double-check expiration (KV TTL should handle this, but be safe)
  if (Date.now() > sessionData.expiresAtMs) {
    await env.SESSIONS_KV.delete(sessionKey);
    return jsonResponse({ error: "Session expired" }, 401);
  }

  return jsonResponse({
    valid: true,
    username: sessionData.username,
    expiresAt: sessionData.expiresAt,
    remainingSeconds: Math.floor(
      (sessionData.expiresAtMs - Date.now()) / 1000
    ),
  });
}

async function handleRefreshSession(request, env) {
  if (request.method !== "POST") {
    return jsonResponse({ error: "Method Not Allowed" }, 405);
  }

  const oldToken = extractBearerToken(request);
  if (!oldToken) {
    return jsonResponse({ error: "Missing or invalid authorization token" }, 401);
  }

  const oldSessionKey = `session:${oldToken}`;
  const sessionDataRaw = await env.SESSIONS_KV.get(oldSessionKey);

  if (!sessionDataRaw) {
    return jsonResponse({ error: "Invalid or expired session" }, 401);
  }

  const oldSessionData = JSON.parse(sessionDataRaw);

  // Check if session is still valid
  if (Date.now() > oldSessionData.expiresAtMs) {
    await env.SESSIONS_KV.delete(oldSessionKey);
    return jsonResponse({ error: "Session expired" }, 401);
  }

  // Generate new session token (token rotation)
  const newToken = await generateSessionToken();
  const now = Date.now();
  const expiresAt = now + SESSION_TTL * 1000;
  const clientIP = getClientIP(request);

  const newSessionData = {
    username: oldSessionData.username,
    createdAt: new Date(now).toISOString(),
    expiresAt: new Date(expiresAt).toISOString(),
    expiresAtMs: expiresAt,
    clientIP: clientIP,
    userAgent: request.headers.get("User-Agent") || "unknown",
    refreshedFrom: oldToken.substring(0, 8) + "...", // Partial reference for audit
  };

  // Store new session
  await env.SESSIONS_KV.put(
    `session:${newToken}`,
    JSON.stringify(newSessionData),
    { expirationTtl: SESSION_TTL }
  );

  // Delete old session
  await env.SESSIONS_KV.delete(oldSessionKey);

  // Update user sessions index
  const userSessionsKey = `user_sessions:${oldSessionData.username}`;
  const existingSessions = await env.SESSIONS_KV.get(userSessionsKey, {
    type: "json",
  });
  if (existingSessions) {
    const updatedSessions = existingSessions
      .filter((s) => s.token !== oldToken && s.expiresAtMs > now)
      .concat([
        {
          token: newToken,
          expiresAtMs: expiresAt,
          createdAt: newSessionData.createdAt,
        },
      ]);
    await env.SESSIONS_KV.put(
      userSessionsKey,
      JSON.stringify(updatedSessions),
      { expirationTtl: SESSION_TTL }
    );
  }

  return jsonResponse({
    success: true,
    token: newToken,
    expiresAt: newSessionData.expiresAt,
    expiresIn: SESSION_TTL,
    username: oldSessionData.username,
  });
}